class UserTOTPManager:
    """Manages TOTP secrets and verification for multiple users."""

    def __init__(self, storage_path: str = None):
        self.totp = TOTPGenerator()
        self.storage_path = storage_path or "totp_users.json"
        self._users = self._load_users()

    def _load_users(self) -> dict:
        """Load user data from storage."""
        if os.path.exists(self.storage_path):
            try:
                with open(self.storage_path, 'r') as f:
                    return json.load(f)
            except (json.JSONDecodeError, IOError):
                return {}
        return {}

    def _save_users(self):
        """Save user data to storage."""
        with open(self.storage_path, 'w') as f:
            json.dump(self._users, f, indent=2)

    def enroll_user(self, user_id: str, account_name: str = None,
                    issuer: str = "MyApp") -> dict:
        """
        Enroll a new user for TOTP 2FA.
        Returns the secret and provisioning URI.
        """
        if not user_id:
            raise TOTPError("User ID is required")

        secret = self.totp.generate_secret()
        display_name = account_name or user_id

        provisioning_uri = self.totp.get_provisioning_uri(
            secret, display_name, issuer
        )

        # Store user data (secret should be encrypted at rest in production)
        self._users[user_id] = {
            'secret': secret,
            'account_name': display_name,
            'issuer': issuer,
            'enrolled_at': time.time(),
            'verified': False,  # Must verify initial code before activation
        }
        self._save_users()

        result = {
            'user_id': user_id,
            'secret': secret,
            'provisioning_uri': provisioning_uri,
            'message': 'Scan the QR code with your authenticator app, then verify with a code.',
        }

        return result

    def verify_enrollment(self, user_id: str, code: str) -> bool:
        """Verify the initial TOTP code to complete enrollment."""
        if user_id not in self._users:
            raise TOTPError(f"User {user_id} is not enrolled")

        user_data = self._users[user_id]
        secret = user_data['secret']

        if self.totp.validate_totp(secret, code, user_id=user_id):
            self._users[user_id]['verified'] = True
            self._save_users()
            return True
        return False

    def validate_code(self, user_id: str, code: str) -> bool:
        """Validate a TOTP code for an enrolled and verified user."""
        if user_id not in self._users:
            raise TOTPError(f"User {user_id} is not enrolled")

        user_data = self._users[user_id]

        if not user_data.get('verified', False):
            raise TOTPError(
                f"User {user_id} enrollment is not verified. "
                "Please complete enrollment verification first."
            )

        secret = user_data['secret']
        return self.totp.validate_totp(secret, code, user_id=user_id)

    def remove_user(self, user_id: str):
        """Remove a user's TOTP enrollment."""
        if user_id in self._users:
            del self._users[user_id]
            self._save_users()

    def generate_backup_codes(self, user_id: str, count: int = 10) -> list:
        """Generate one-time backup codes for account recovery."""
        if user_id not in self._users:
            raise TOTPError(f"User {user_id} is not enrolled")

        backup_codes = []
        for _ in range(count):
            # Generate 8-character alphanumeric codes
            code = secrets.token_hex(4).upper()
            # Format as XXXX-XXXX for readability
            formatted = f"{code[:4]}-{code[4:]}"
            backup_codes.append(formatted)

        # Store hashed backup codes
        hashed_codes = []
        for bc in backup_codes:
            # Hash backup codes for storage
            code_hash = hashlib.sha256(
                bc.replace('-', '').encode('utf-8')
            ).hexdigest()
            hashed_codes.append(code_hash)

        self._users[user_id]['backup_codes'] = hashed_codes
        self._save_users()

        return backup_codes

    def validate_backup_code(self, user_id: str, code: str) -> bool:
        """Validate and consume a backup code."""
        if user_id not in self._users:
            raise TOTPError(f"User {user_id} is not enrolled")

        user_data = self._users[user_id]
        stored_codes = user_data.get('backup_codes', [])

        if not stored_codes:
            return False

        # Hash the provided code
        normalized = code.replace('-', '').replace(' ', '').upper()
        code_hash = hashlib.sha256(normalized.encode('utf-8')).hexdigest()

        # Constant-time search through all codes to prevent timing attacks
        found_index = -1
        for i, stored_hash in enumerate(stored_codes):
            if hmac.compare_digest(code_hash, stored_hash):
                found_index = i

        if found_index >= 0:
            # Remove the used backup code
            stored_codes.pop(found_index)
            self._users[user_id]['backup_codes'] = stored_codes
            self._save_users()
            return True

        return False

    def is_enrolled(self, user_id: str) -> bool:
        """Check if a user is enrolled for TOTP."""
        return user_id in self._users

    def is_verified(self, user_id: str) -> bool:
        """Check if a user's enrollment is verified."""
        if user_id not in self._users:
            return False
        return self._users[user_id].get('verified', False)

    def get_qr_code(self, user_id: str, file_path: str = None) -> bytes:
        """Generate QR code for an enrolled user."""
        if user_id not in self._users:
            raise TOTPError(f"User {user_id} is not enrolled")

        user_data = self._users[user_id]
        return self.totp.generate_qr_code(
            user_data['secret'],
            user_data['account_name'],
            user_data['issuer'],
            file_path
        )


